def ensure_admin():
    if ctypes.windll.shell32.IsUserAnAdmin():
        return True
    print("[→] 请求管理员权限...")
    ctypes.windll.shell32.ShellExecuteW(None, "runas", sys.executable, " ".join(sys.argv), None, 1)
    sys.exit()

ensure_admin()
base64_str = ""
# 这里放入你的 uiaccess.dll 的 base64 字符串，必须替换为你的 DLL 完整编码
import os
import sys
import ctypes
from ctypes import wintypes
import time
import shutil

# 目标程序名称
target_exe = "Adobe™ TDOUT®.exe"
target_dll = "uiaccess.dll"

# 获取当前目录
current_dir = os.getcwd()
target_exe_path = os.path.join(current_dir, target_exe)
current_dll_path = os.path.join(current_dir, target_dll)
system_dll_path = r"C:\Windows\System32\uiaccess.dll"

# 判断exe是否已存在，如果不存在则从资源中提取
if os.path.exists(target_exe_path):
    print(f"{target_exe_path} 已存在")
else:
    try:
        # 判断运行环境，定位资源位置
        if getattr(sys, 'frozen', False):
            # 打包后的环境
            meipass = sys._MEIPASS
            resource_path = os.path.join(meipass, target_exe)

            if os.path.exists(resource_path):
                print(f"正在从资源中提取 {target_exe} 到当前目录")
                shutil.copy2(resource_path, target_exe_path)
                print(f"提取完成: {target_exe_path}")
            else:
                print(f"错误：在资源中未找到 {target_exe}")
                sys.exit(1)

        else:
            # 开发环境，假设exe在相同目录
            script_dir = os.path.dirname(os.path.abspath(__file__))
            dev_exe_path = os.path.join(script_dir, target_exe)

            if os.path.exists(dev_exe_path):
                shutil.copy2(dev_exe_path, target_exe_path)
                print(f"开发环境：已复制 {target_exe} 到当前目录")
            else:
                print(f"错误：未找到 {target_exe}，请确保文件存在")
                sys.exit(1)

    except Exception as e:
        print(f"EXE提取失败：{e}")
        sys.exit(1)


# === DLL 创建操作 ===
def create_dll_from_base64():
    """从base64创建DLL文件到当前目录和系统目录"""
    try:
        # 解码base64数据
        print("正在解码base64 DLL数据...")
        decoded_data = base64.b64decode(base64_str)
        print(f"DLL数据解码成功，大小: {len(decoded_data)} 字节")

        # 写入到当前目录
        if not os.path.exists(current_dll_path):
            with open(current_dll_path, 'wb') as f:
                f.write(decoded_data)
            print(f"DLL已创建到当前目录: {current_dll_path}")
        else:
            print(f"DLL已存在于当前目录: {current_dll_path}")

        # 写入到系统目录（需要管理员权限）
        kernel32 = ctypes.WinDLL('kernel32', use_last_error=True)
        old_value = ctypes.c_void_p()
        redirect_disabled = False

        try:
            # 禁用文件系统重定向（32位Python在64位系统）
            if kernel32.Wow64DisableWow64FsRedirection(ctypes.byref(old_value)):
                redirect_disabled = True

            if not os.path.exists(system_dll_path):
                # 需要管理员权限才能写入系统目录
                with open(system_dll_path, 'wb') as f:
                    f.write(decoded_data)
                print(f"DLL已创建到系统目录: {system_dll_path}")
            else:
                print(f"DLL已存在于系统目录: {system_dll_path}")

        except PermissionError:
            print("错误：权限不足，无法写入系统目录！请以管理员身份运行。")
            return False
        except Exception as e:
            print(f"写入系统目录失败: {e}")
            return False
        finally:
            # 恢复文件系统重定向
            if redirect_disabled:
                kernel32.Wow64RevertWow64FsRedirection(old_value)

        return True

    except base64.binascii.Error as e:
        print(f"Base64 解码失败：{e}")
        return False
    except Exception as e:
        print(f"DLL创建失败: {e}")
        return False


# 执行DLL创建
dll_created = create_dll_from_base64()

# === 加载 DLL 并启动进程 ===
try:
    # 优先使用系统目录的DLL，如果不存在则使用当前目录的DLL
    if os.path.exists(system_dll_path):
        dll_to_load = system_dll_path
    elif os.path.exists(current_dll_path):
        dll_to_load = current_dll_path
    else:
        print("错误：未找到可用的DLL文件")
        dll_to_load = None

    if dll_to_load:
        print(f"正在加载DLL: {dll_to_load}")
        uiaccess = ctypes.WinDLL(dll_to_load, use_last_error=True)

        # 定义函数原型
        IsProcessElevated = uiaccess.IsProcessElevated
        IsProcessElevated.argtypes = [wintypes.HANDLE]
        IsProcessElevated.restype = wintypes.BOOL

        StartUIAccessProcess = uiaccess.StartUIAccessProcess
        StartUIAccessProcess.argtypes = [
            wintypes.LPCWSTR,  # lpApplicationName
            wintypes.LPCWSTR,  # lpCommandLine
            wintypes.DWORD,  # flag
            ctypes.POINTER(wintypes.DWORD),  # pPid
            wintypes.DWORD  # dwSession
        ]
        StartUIAccessProcess.restype = wintypes.BOOL

        # 检查管理员权限
        if not IsProcessElevated(wintypes.HANDLE(-1)):
            print("错误：程序必须以管理员权限运行!")
            sys.exit(1)

        # 获取当前进程ID和会话ID
        kernel32 = ctypes.WinDLL('kernel32', use_last_error=True)
        GetCurrentProcessId = kernel32.GetCurrentProcessId
        GetCurrentProcessId.restype = wintypes.DWORD

        ProcessIdToSessionId = kernel32.ProcessIdToSessionId
        ProcessIdToSessionId.argtypes = [wintypes.DWORD, ctypes.POINTER(wintypes.DWORD)]
        ProcessIdToSessionId.restype = wintypes.BOOL

        pid_current = GetCurrentProcessId()
        session_id = wintypes.DWORD(0)
        if not ProcessIdToSessionId(pid_current, ctypes.byref(session_id)):
            raise ctypes.WinError(ctypes.get_last_error())

        # 启动目标进程
        app_name = None
        flag = 0
        pid = wintypes.DWORD(0)
        target_session_id = session_id.value

        success = StartUIAccessProcess(
            app_name,
            target_exe_path,  # 使用当前目录的exe路径
            flag,
            ctypes.byref(pid),
            target_session_id
        )

        if success:
            print(f"通过DLL成功启动进程! PID: {pid.value}")
        else:
            error = ctypes.WinError(ctypes.get_last_error())
            print(f"DLL启动失败: {error}")
            # DLL启动失败时尝试直接启动
            raise Exception("DLL启动失败，尝试直接启动")
    else:
        # 没有DLL时直接启动
        raise Exception("未找到DLL文件，尝试直接启动")

except Exception as e:
    print(f"DLL启动方式失败: {e}")
    # 出错时尝试直接启动
    try:
        print("正在尝试直接启动程序...")
        os.startfile(target_exe_path)
        print(f"已直接启动: {target_exe_path}")
    except Exception as start_error:
        print(f"直接启动也失败: {start_error}")

